{"operationName":"Token","variables":{"chain":"ETHEREUM"},"query":"query Token($chain: Chain!, $address: String) {
  token(chain: $chain, address: $address) {
    ...TokenParts
    __typename
  }
}

fragment TokenParts on Token {
  ...TokenBasicInfoParts
  ...TokenBasicProjectParts
  ...TokenFeeDataParts
  ...TokenProtectionInfoParts
  __typename
}

fragment TokenBasicInfoParts on Token {
  id
  address
  chain
  decimals
  name
  standard
  symbol
  isBridged
  bridgedWithdrawalInfo {
    chain
    provider
    url
    __typename
  }
  __typename
}

fragment TokenBasicProjectParts on Token {
  project {
    id
    isSpam
    logoUrl
    name
    safetyLevel
    spamCode
    tokens {
      chain
      address
      __typename
    }
    __typename
  }
  __typename
}

fragment TokenFeeDataParts on Token {
  feeData {
    buyFeeBps
    sellFeeBps
    __typename
  }
  __typename
}

fragment TokenProtectionInfoParts on Token {
  protectionInfo {
    result
    attackTypes
    blockaidFees {
      buy
      sell
      transfer
      __typename
    }
    __typename
  }
  __typename
}"}

